import Link from "next/link";
import { Tag, MapPin, Calendar, ArrowRight } from "lucide-react";

const Card = ({ item }) => {
  const getStatusStyle = (status) => {
    switch (status?.toLowerCase()) {
      case "pending":
        return "bg-amber-100 text-amber-700 border-amber-200";
      case "accepted":
        return "bg-emerald-100 text-emerald-700 border-emerald-200";
      case "rejected":
        return "bg-rose-100 text-rose-700 border-rose-200";
      default:
        return "bg-gray-100 text-gray-600 border-gray-200";
    }
  };

  const formatDate = (dateStr) => {
    const d = new Date(dateStr);
    return d.toLocaleDateString("en-GB");
  };

  return (
    <div className="group relative flex flex-col md:flex-row bg-white border border-gray-100 rounded-2xl overflow-hidden hover:shadow-2xl hover:shadow-indigo-100 transition-all duration-500 w-full max-w-2xl h-auto md:h-56">
      {/* LEFT SIDE: IMAGE CONTAINER */}
      <div className="relative w-full md:w-2/5 h-48 md:h-full overflow-hidden">
        <img
          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
          src={
            item.photos?.[0] ||
            "https://placehold.co/400x400/4F46E5/FFFFFF?text=Item"
          }
          alt={item.itemName}
        />
        {/* Floating Status on Image */}
        <div
          className={`absolute top-3 left-3 px-3 py-1 text-[10px] font-black uppercase tracking-widest rounded-full border backdrop-blur-md ${getStatusStyle(item.status)}`}
        >
          {item.status}
        </div>
      </div>

      {/* RIGHT SIDE: CONTENT */}
      <div className="flex flex-col justify-between p-6 w-full md:w-3/5 bg-gradient-to-br from-white to-indigo-50/30">
        <div>
          <div className="flex justify-between items-start">
            <h3 className="text-xl font-black text-gray-800 group-hover:text-indigo-600 transition-colors duration-300">
              {item.itemName}
            </h3>
          </div>

          <div className="grid grid-cols-1 gap-y-1.5 mt-3">
            <div className="flex items-center text-xs font-medium text-gray-500">
              <Tag className="w-3.5 h-3.5 mr-2 text-indigo-400" />
              {item.category || "General"}
            </div>
            <div className="flex items-center text-xs font-medium text-gray-500">
              <MapPin className="w-3.5 h-3.5 mr-2 text-indigo-400" />
              {item.location}
            </div>
            <div className="flex items-center text-xs font-medium text-gray-500">
              <Calendar className="w-3.5 h-3.5 mr-2 text-indigo-400" />
              {formatDate(item.date)}
            </div>
          </div>
        </div>

        {/* ACTIONS */}
        <div className="flex items-center gap-3 mt-4">
          <Link href={`/claimItem/${item._id}`} className="flex-1">
            <button className="w-full py-2.5 bg-indigo-600 hover:bg-black text-white rounded-xl text-sm font-bold transition-all duration-300 transform active:scale-95 shadow-lg shadow-indigo-100">
              Claim Now
            </button>
          </Link>

          <Link href={`/item/${item._id}`}>
            <button className="p-2.5 bg-white border border-gray-200 text-gray-400 hover:text-indigo-600 hover:border-indigo-600 rounded-xl transition-all duration-300 group/btn">
              <ArrowRight className="w-5 h-5 group-hover/btn:translate-x-1 transition-transform" />
            </button>
          </Link>
        </div>
      </div>
    </div>
  );
};

export default Card;
